use postgres::{Client, NoTls};

fn search_users_by_email(email: String) -> Vec<User> {
    let mut client = Client::connect("postgres://user@localhost", NoTls).unwrap();

    // build the query dynamically
    let query = format!("SELECT * FROM users WHERE email = '{}'", email);

    // execute the query and retrieve results
    let result = client.query(query, &[]).unwrap();

    // convert the results to a Vec<User>
    let mut users: Vec<User> = vec![];
    for row in result {
        let user = User {
            id: row.get("id"),
            email: row.get("email"),
            name: row.get("name"),
        };
        users.push(user);
    }

    users
}